#include<bits/stdc++.h>
using namespace std;
int dp[2005],dp1[2005];
int num[2005];
int main()
{
	int n;
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>num[i];
		dp[i]=1;
		dp1[i]=1;
	}
	for(int i=1;i<=n;i++){
		for(int j=1;j<i;j++){
			if(num[j]<num[i]){
				dp[i]=max(dp[i],dp[j]+1);
			}
		}
	}
	for(int i=n;i>=1;i--){
		for(int j=n;j>i;j--){
			if(num[j]<num[i]){
				dp1[i]=max(dp1[i],dp1[j]+1);
			}
		}
	}
//	for(int i=1;i<=n;i++){
//		cout<<dp[i]<<' ';
//	}
//	cout<<endl;
//	for(int i=1;i<=n;i++){
//		cout<<dp1[i]<<' ';
//	}
	int maxi=0;
	for(int i=1;i<=n;i++){
		maxi=max(dp[i]+dp1[i]-1,maxi);
	}
	cout<<n-maxi;
}
